var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"안색이 어두워 보이네. 어디 다쳤으면 내가 봐 줄까?","JPN":"顔色がよくないけど、どこか怪我でもしてるの？","ENG":"Why do you look so gloomy? If you're hurt, I can take a look at you.","TWN":"妳的臉色看起來不太好，是不是受傷了，要我幫妳看看嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아, 괜찮아요. 무슨 일이세요?","JPN":"いえ、大丈夫です。それより、何でしょうか？","ENG":"Ah, it's okay. Is something going on?","TWN":"啊，沒事，怎麼了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"메이드장이 사람들을 모으고 있어. 앞으로 어떻게 할지 논의하려나 봐.","JPN":"メイド長が呼んでるわ。これからどうするか議論したいみたい。","ENG":"The Chief Maid is gathering people. I think she wants to discuss what to do.","TWN":"女僕長讓我們都過去，應該是想商量之後的對策。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그런데 그쪽은 불러도 대답이 없던걸?","JPN":"ずっと呼んでたのに、返事がないから……","ENG":"I called you several times, and you didn't answer.","TWN":"但怎麼叫妳都沒有反應。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"무슨 생각을 그렇게 깊이 하고 있었어?","JPN":"そんな考え込んで、どうかしたの？","ENG":"What are you thinking so hard?","TWN":"妳想什麼想的這麼入迷？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"별건 아니에요. 그냥 석연치 않은 것들이 좀 있어서요.","JPN":"いえ、何でもないです。ただちょっと、釈然としないことがあって。","ENG":"Nothing, but there are some things that don't add up.","TWN":"沒什麼，就是總感覺有點不對勁。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"석연치 않은 것?","JPN":"釈然としないこと？","ENG":"Things that don't add up?","TWN":"不對勁？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그러니까 그 녀석만 잡으면 이 난리도 끝이잖아.","JPN":"だから、あいつさえ捕まえればこの騒ぎも終わるでしょ？","ENG":"So, we can put an end to this once we catch him.","TWN":"只要抓到那個傢伙，就能結束這場鬧劇了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"더 고민할 게 뭐가 있어?","JPN":"悩む必要なんかないと思うんだけど。","ENG":"What else is there to worry about?","TWN":"有什麼可想的？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"쉽게 생각할 일은 아닙니다.","JPN":"でも、そう簡単ではありません。","ENG":"It's not an issue to be taken lightly.","TWN":"這件事沒這麼簡單。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"파티를 열고 시간이 상당히 흘렀습니다.","JPN":"パーティーが始まって、かなりの時間が過ぎました。","ENG":"It's been hours since the party began.","TWN":"從派對開始到現在，已經過去了很長時間。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"경솔하게 움직이면 범인의 함정에 빠질 수도 있어요.","JPN":"軽率に動けば、犯人の罠にハマる可能性もあります。","ENG":"If we make a rash move, we can fall right into his trap.","TWN":"如果輕舉妄動，一不小心就會陷入兇手設下的陷阱。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"저쪽은 의견 통일이 잘 안 되나 보네.","JPN":"あっちは意見が合わないようね。","ENG":"It seems they're having a difference of opinion.","TWN":"那邊好像還在爭執不休。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"우리도 가 볼까?","JPN":"私たちも行ってみましょう。","ENG":"Let's go join them, shall we?","TWN":"我們也去看看吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네, 그러죠.","JPN":"はい、そうですね。","ENG":"Sure.","TWN":"好，走吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아, 답답해. 왜 그렇게 꽉 막혔어?","JPN":"あぁ、もう話になんない。どうしてそう石頭なわけ？","ENG":"Argh, I can't talk to you. Why are you being so stubborn?","TWN":"真是煩人，怎麼那麼死心眼啊？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"일단 흩어졌다가 녀석을 찾은 사람이 신호를 보내면 되지.","JPN":"ひとまずみんなで手分けして探して、見つけたら合図を送ればいいじゃない。","ENG":"I'm saying, we should scatter and whoever finds him first signals the rest of us.","TWN":"我們各自散開，誰找到那個傢伙就發出信號。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"효율적인 방법이라는 건 인정하지만 위험도가 너무 높습니다.","JPN":"効率的な方法だということは認めます。しかし、危険度が高すぎます。","ENG":"I agree that your method is effective, but it's too risky.","TWN":"那個辦法雖然效率高，但太危險了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"이런 고립된 곳에서 흩어지는 건 흔한 전멸 클리셰에요.","JPN":"こんな孤立した所で散らばるのは、よくある全滅フラグです。","ENG":"Such a divide-and-conquer strategy can easily lead us to complete annihilation in this isolated space.","TWN":"在這種孤立的地方一旦散開，就很容易全軍覆沒。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"말씀드린 대로 모두 함께 움직이는 것이 가장 안전합니다.","JPN":"さっきも話した通り、みんなで一緒に動いた方が安全です。","ENG":"I stand by my opinion that we should stick together.","TWN":"所以就像我所說，我們一起行動是最安全的。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아니, 그래서 어느 세월에 범인을 잡아? 그러다 날새겠다!","JPN":"そしたら、いつになったら犯人を見つけられるわけ？　徹夜でもする気？","ENG":"But if we do, we won't be able to catch him!","TWN":"那我們猴年馬月才能抓到兇手？估計天都亮了！"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"동이 틀 때까지 범인을 못 잡으면 희생자들이 위험해진다면서?","JPN":"夜が明けるまで犯人を見つけられなかったら、犠牲者たちが助からないかもしれないんでしょ？","ENG":"We have to catch him before dawn, or his victims will be in danger. Am I wrong?","TWN":"不是說天亮之前抓不到兇手，受害者就很危險嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"그건 그렇습니다만......","JPN":"それはそうですが……","ENG":"No, but...","TWN":"妳說的沒錯……"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"제 생각에도 흩어지는 건 위험 부담이 클 것 같아요.","JPN":"私も散らばるのは危険かと思います。","ENG":"I agree with Veronica. It's too dangerous for us to scatter.","TWN":"我也認為各自散開是很危險的。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"겉보기엔 빈틈투성이 같아도 선배는 그렇게 호락호락한 사람이 아니거든요.","JPN":"一見隙だらけに思えても、先輩はそう容易い相手ではありません。","ENG":"Shiyoon is not as sloppy as he looks.","TWN":"前輩雖然看起來冒冒失失的，但絕對不是一個吃素的。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런 선배가 큰 이벤트를 준비했다고 말할 정도면 우리도 최악의 상황을 가정해야 해요.","JPN":"そんな先輩が大きなイベントを準備すると言ったとなれば、私たちも最悪の状況を仮定しなければなりません。","ENG":"If he's preparing drastic methods, then it's got to be serious. It could be the end of us.","TWN":"他既然揚言說為我們準備驚喜，那我們有必要想好最壞的情況。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아, 진짜! 내 편은 아무도 없어?!","JPN":"もう！　アタシの味方は誰もいないわけ！？","ENG":"Argh, seriously? Why isn't anyone taking my side?","TWN":"天啊！就沒有人站我這一邊嗎？！"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"알렉스인가 하는 사람은 어디 있어? 그 사람한테도 물어 보자고!","JPN":"アレックスとかいう人は、どこ行ったの？　あの人にも聞いてみるわよ！","ENG":"Where's that woman, Alex? I want her opinion on this, too!","TWN":"那個叫雅蕾克絲的去哪裡了？我們也問問她吧！"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"응? 알렉스 씨라면 방금 나랑 같이 왔는데?","JPN":"えっ？　アレックスさんなら、さっき私と一緒に来たけど？","ENG":"Huh? She just came here with me.","TWN":"嗯？雅蕾克絲剛剛和我一起過來的啊？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"알렉스 님, 어디 가셨던 검까? 또 사라지신 줄 알았지 말임다.","JPN":"アレックス様、どこに行ったっすか？　また消えたと思ったっす。","ENG":"Ms. Alex, where have you been? I thought you disappeared on us again, ma'am.","TWN":"雅蕾克絲小姐，您去哪裡了？還以為您又消失了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"혹시나 해서 바깥 경계를 하고 있었어.","JPN":"念のために外の見回りをしてたんだけど。","ENG":"I went outside to check the perimeter.","TWN":"以防萬一，我查看了一下外面的情況。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그런데...... 다들 나와서 한 번 봐 줄래?","JPN":"みんなにちょっと、見てもらいたいものがあるの。","ENG":"And... could you guys come out and take a look at something?","TWN":"不過……妳們都來看看吧。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"아무래도 일이 커진 것 같거든.","JPN":"ちょっと大変なことになっちゃったみたい。","ENG":"I think we're in bigger trouble than we thought.","TWN":"看來事情一發不可收拾了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"네? 그게 무슨 말씀이심까?","JPN":"え？　それってどういう……","ENG":"Pardon? What do you mean, ma'am?","TWN":"什麼？您這是什麼意思？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"엄마야?!","JPN":"ビックリしたっ！？","ENG":"Wah!","TWN":"天啊？！"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐야? 그 주시윤인가 하는 녀석이 또 습격해 온 거야?","JPN":"えっ？　あのアキヤマ・シリュウとかいう奴がまた襲ってきたの？","ENG":"What? Did that Shiyoon guy attack again?","TWN":"什麼啊？不會是周時雲那個傢伙又搞什麼襲擊吧？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"아뇨. 그보다 훨씬 나쁜 일 같습니다.","JPN":"いえ、それよりずっと悪いことです。","ENG":"No, but something much worse did.","TWN":"不是，不過比那個更糟糕。"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"훨씬 나빠? 좀비 아포칼립스라도 시작됐어?","JPN":"ずっと悪い？　ゾンビの集団でも襲って来たとか？","ENG":"Something much worse? Like what, zombies?","TWN":"更糟糕？難道是僵屍襲來了不成？"},"stage":{"bg":"X_MAS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"성야의...... 살인마가 온다......","JPN":"聖夜の……殺人鬼がやってくる……","ENG":"Here comes... the Killer of the Holy Night...","TWN":"耶誕的……嫌疑犯來了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"포기하라...... 희망은 없다......","JPN":"諦めろ……もう希望はない……","ENG":"Give up... There's no hope...","TWN":"放棄吧……陷入絕望吧……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"성야의 저주는...... 아무도 피할 수 없다......","JPN":"聖夜の呪いは……誰も避けられない……","ENG":"No one's safe... from the Curse of the Holy Night...","TWN":"誰也無法避開……耶誕的詛咒……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"쓰, 쓰러졌던 분들이 다시 일어나서 쳐들어 오고 계시지 말임다!","JPN":"た、倒れてた人たちが起き上がって、こっちに来てるっす！","ENG":"Th-the fallen have returned, ma'am! And they are attacking us!","TWN":"倒、倒下的人都站起來攻擊過來了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"분명히 싸울 때 휘말리지 말라고 빈 방에 모셔다 뒀는데......?","JPN":"戦闘に巻き込まれないように、別室に運んでおいたっすけど……","ENG":"But we moved them to an empty room, away from the fight scene.","TWN":"可是我明明把他們都放到空房裡了啊……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"추리물이든 슬래셔든 오컬트든 하나만 하라고 해, 진짜!","JPN":"推理かオカルトかスラッシャーか、どれか一つにしてよね！","ENG":"Is this a mystery, slasher, or occult story? Seriously, make up your mind!","TWN":"這到底是推理、殺人還是靈異啊，這也太混搭了，真是的！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배가 말했던 극적인 이벤트가...... 설마 이거였어?","JPN":"先輩が言っていた劇的なイベントが……まさかこれ？","ENG":"Can this be the drastic method that Shiyoon told us about?","TWN":"這就是前輩所說的……驚喜？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"서윤 님, 고민은 나중에. 지금은 더 늦기 전에 저 분들을 진정시켜야 합니다.","JPN":"アオイ様、今はまずあの方々を大人しくさせるのが先です。","ENG":"We can think about it later, Ms. Seo Yoon. For now, let's calm them down before it's too late.","TWN":"徐芸小姐，現在不是想那個的時候，最要緊的是先讓他們冷靜下來。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......알겠어요! 조금만 더 도와 주세요, 베로니카 씨!","JPN":"……わかりました！　もう少しだけ手伝ってください、ベロニカさん！","ENG":"Okay. Please help us more, Veronica.","TWN":"……知道了！再幫我一把，貝洛妮卡！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"성난 손님을 상대하는 것도 메이드의 일이죠. 맡겨 주시길.","JPN":"怒ったお客様のお相手をするのも、メイドの仕事です。お任せください。","ENG":"We maids are also trained to handle unhappy guests. You can count on us.","TWN":"哄勸生氣的客人也是女僕該做的事，就交給我吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};